}","language":"typescript"},"narration":"At the Normalization Pass, chaos becomes order. Every messaging platform has its own format. The ChannelPlugin interface forces them all into one shape. The gateway never needs to know whether you messaged from WhatsApp or Telegram."},{"name":"Route Resolution Fork","subtitle":"Finding the Right Agent","concept":"Route Resolution","landmarkType":"mountain","code":{"file":"src/routing/resolve-route.ts","content":"// src/routing/resolve-route.ts (simplified)
export function resolveAgentRoute({
  cfg, channel, accountId, peer, guildId, teamId,
}: ResolveRouteInput): ResolvedRoute {

  for (const agent of cfg.agents.list) {
    const routing = agent.routing

    // 1. Exact peer match (highest priority)
    const peerMatch = routing.peer?.find(
      b => b.peer === peer.id && b.channel === channel
    )
    if (peerMatch) return { agentId: agent.id, matchedBy: 'peer' }

    // 2. Guild/server match
    const guildMatch = routing.guild?.find(
      b => b.guildId === guildId && b.channel === channel
    )
    if (guildMatch) return { agentId: agent.id, matchedBy: 'guild' }

    // 3. Account-level match
    const accountMatch = routing.account?.find(
      b => b.accountId === accountId && b.channel === channel
    )
    if (accountMatch) return { agentId: agent.id, matchedBy: 'account' }
  }

  return { agentId: cfg.agents.default, matchedBy: 'default' }
}","language":"typescript"},"narration":"Here's where the trail forks. The resolver checks priority order: specific peer binding, then guild/server, then account, then default. One gateway can serve different agents to different people."},{"name":"Session Persistence Camp","subtitle":"Loading Conversation State","concept":"Session Persistence","landmarkType":"camp","code":{"file":"src/sessions/session-utils.ts","content":"// src/sessions/session-utils.ts (simplified)
